import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import SearchBar from './SearchBar';


const Navbar = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const navigate = useNavigate();

  const styles = {
    navbar: {
      background: 'linear-gradient(90deg, #4f46e5 0%, #7c3aed 100%)',
      color: 'white',
      padding: '1rem 2rem',
      boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
      position: 'sticky',
      top: 0,
      zIndex: 1000
    },
    container: {
      maxWidth: '1200px',
      margin: '0 auto',
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center'
    },
    logo: {
      display: 'flex',
      alignItems: 'center',
      gap: '10px',
      fontSize: '1.5rem',
      fontWeight: 'bold',
      textDecoration: 'none',
      color: 'white'
    },
    logoIcon: {
      fontSize: '1.8rem'
    },
    navLinks: {
      display: 'flex',
      gap: '2rem',
      alignItems: 'center',
      '@media (max-width: 768px)': {
        display: isMenuOpen ? 'flex' : 'none',
        flexDirection: 'column',
        position: 'absolute',
        top: '100%',
        left: 0,
        right: 0,
        background: '#4f46e5',
        padding: '1rem',
        zIndex: 1000
      }
    },
    link: {
      color: 'white',
      textDecoration: 'none',
      fontSize: '1rem',
      transition: 'all 0.3s',
      padding: '0.5rem 1rem',
      borderRadius: '5px',
      '&:hover': {
        background: 'rgba(255,255,255,0.1)'
      }
    },
    authButtons: {
      display: 'flex',
      gap: '1rem',
      alignItems: 'center'
    },
    loginBtn: {
      background: 'transparent',
      color: 'white',
      border: '2px solid white',
      padding: '0.5rem 1.5rem',
      borderRadius: '25px',
      fontWeight: 'bold',
      cursor: 'pointer',
      transition: 'all 0.3s',
      '&:hover': {
        background: 'white',
        color: '#4f46e5'
      }
    },
    registerBtn: {
      background: 'white',
      color: '#4f46e5',
      border: 'none',
      padding: '0.5rem 1.5rem',
      borderRadius: '25px',
      fontWeight: 'bold',
      cursor: 'pointer',
      transition: 'all 0.3s',
      '&:hover': {
        background: '#f8f9fa',
        transform: 'translateY(-2px)'
      }
    },
    menuButton: {
      display: 'none',
      background: 'none',
      border: 'none',
      color: 'white',
      fontSize: '1.5rem',
      cursor: 'pointer',
      padding: '0.5rem',
      '@media (max-width: 768px)': {
        display: 'block'
      }
    },
    dropdown: {
      position: 'relative',
      display: 'inline-block'
    },
    dropdownContent: {
      display: 'none',
      position: 'absolute',
      background: 'white',
      minWidth: '200px',
      boxShadow: '0 8px 16px rgba(0,0,0,0.2)',
      borderRadius: '8px',
      zIndex: 1,
      top: '100%',
      left: 0
    },
    dropdownLink: {
      color: '#333',
      padding: '12px 16px',
      textDecoration: 'none',
      display: 'block',
      '&:hover': {
        background: '#f1f1f1'
      }
    },
    courseLink: {
      position: 'relative',
      '&:hover .dropdownContent': {
        display: 'block'
      }
    }
  };

  return (
    <>
      <nav style={styles.navbar}>
        <div style={styles.container}>
          <Link to="/" style={styles.logo}>
            <span style={styles.logoIcon}>📚</span>
            <span>Study Portal</span>
          </Link>

          <button 
            style={styles.menuButton}
            onClick={() => setIsMenuOpen(!isMenuOpen)}
          >
            {isMenuOpen ? '✕' : '☰'}
          </button>

          <div style={styles.navLinks}>
            <Link to="/" style={styles.link}>Home</Link>
            
            {/* Courses Dropdown */}
            <div style={styles.courseLink}>
              <Link to="/courses" style={styles.link}>
                Courses ▼
              </Link>
              <div style={styles.dropdownContent}>
                <Link to="/course/1" style={styles.dropdownLink}>🎓 B.Tech</Link>
                <Link to="/course/2" style={styles.dropdownLink}>📱 BCA</Link>
                <Link to="/course/3" style={styles.dropdownLink}>📊 BBA</Link>
                <Link to="/course/4" style={styles.dropdownLink}>💼 MBA</Link>
                <Link to="/course/5" style={styles.dropdownLink}>💻 MCA</Link>
              </div>
            </div>
            
            <Link to="/upload" style={styles.link}>Upload</Link>
            <Link to="/about" style={styles.link}>About</Link>
            
            <div style={styles.authButtons}>
              <button 
                onClick={() => navigate('/login')}
                style={styles.loginBtn}
              >
                Login
              </button>
              <button 
                onClick={() => navigate('/register')}
                style={styles.registerBtn}
              >
                Register
              </button>
            </div>
          </div>
        </div>
      </nav>
    </>
  );
};

export default Navbar;
